<?php/** * The header for our theme * * This is the template that displays all of the <head> section and everything up until <div id="content"> * * @link https://developer.wordpress.org/themes/basics/template-files/#template-partials * * @package AquaLuxe */?><!doctype html><html <?php language_attributes(); ?> class="<?php echo aqualuxe_get_html_classes(); ?>"><head>	<meta charset="<?php bloginfo( 'charset' ); ?>">	<meta name="viewport" content="width=device-width, initial-scale=1">	<link rel="profile" href="https://gmpg.org/xfn/11">	<?php wp_head(); ?></head><body <?php body_class(); ?>><?php wp_body_open(); ?><div id="page" class="site">	<a class="skip-link screen-reader-text" href="#primary"><?php esc_html_e( 'Skip to content', 'aqualuxe' ); ?></a>	<?php do_action( 'aqualuxe_before_header' ); ?>	<header id="masthead" class="site-header">		<?php get_template_part( 'templates/parts/header', 'topbar' ); ?>		<div class="header-main bg-white dark:bg-dark-800 shadow-soft transition-colors duration-300">			<div class="container mx-auto px-4">				<div class="flex items-center justify-between py-4">					<div class="site-branding flex items-center">						<?php						if ( has_custom_logo() ) :							the_custom_logo();						else :							?>							<h1 class="site-title">								<a href="<?php echo esc_url( home_url( '/' ) ); ?>" rel="home" class="text-primary-700 dark:text-primary-400 text-2xl font-serif font-bold hover:text-primary-600 transition-colors duration-300">									<?php bloginfo( 'name' ); ?>								</a>							</h1>							<?php							$aqualuxe_description = get_bloginfo( 'description', 'display' );							if ( $aqualuxe_description || is_customize_preview() ) :								?>								<p class="site-description ml-4 text-gray-600 dark:text-gray-400 text-sm hidden md:block">									<?php echo $aqualuxe_description; // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped ?>								</p>							<?php endif; ?>						<?php endif; ?>					</div><!-- .site-branding -->					<nav id="site-navigation" class="main-navigation hidden lg:block">						<?php						wp_nav_menu(							array(								'theme_location' => 'primary',								'menu_id'        => 'primary-menu',								'menu_class'     => 'flex space-x-6',								'container'      => false,								'fallback_cb'    => false,								'depth'          => 2,								'walker'         => new AquaLuxe_Walker_Nav_Menu(),							)						);						?>					</nav><!-- #site-navigation -->					<div class="header-actions flex items-center space-x-4">						<?php if ( get_theme_mod( 'aqualuxe_enable_dark_mode', true ) ) : ?>							<button id="dark-mode-toggle" class="dark-mode-toggle text-gray-700 dark:text-gray-300 hover:text-primary-600 dark:hover:text-primary-400 transition-colors duration-300" aria-label="<?php esc_attr_e( 'Toggle dark mode', 'aqualuxe' ); ?>">								<svg xmlns="http://www.w3.org/2000/svg" class="h-6 w-6 dark:hidden" fill="none" viewBox="0 0 24 24" stroke="currentColor">									<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />								</svg>								<svg xmlns="http://www.w3.org/2000/svg" class="h-6 w-6 hidden dark:block" fill="none" viewBox="0 0 24 24" stroke="currentColor">									<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />								</svg>							</button>						<?php endif; ?>						<?php if ( get_theme_mod( 'aqualuxe_enable_search', true ) ) : ?>							<button id="search-toggle" class="search-toggle text-gray-700 dark:text-gray-300 hover:text-primary-600 dark:hover:text-primary-400 transition-colors duration-300" aria-label="<?php esc_attr_e( 'Toggle search', 'aqualuxe' ); ?>">								<svg xmlns="http://www.w3.org/2000/svg" class="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">									<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />								</svg>							</button>						<?php endif; ?>						<?php if ( class_exists( 'WooCommerce' ) && get_theme_mod( 'aqualuxe_enable_minicart', true ) ) : ?>							<div class="mini-cart-wrapper relative">								<a href="<?php echo esc_url( wc_get_cart_url() ); ?>" class="mini-cart-toggle text-gray-700 dark:text-gray-300 hover:text-primary-600 dark:hover:text-primary-400 transition-colors duration-300" aria-label="<?php esc_attr_e( 'View your shopping cart', 'aqualuxe' ); ?>">									<svg xmlns="http://www.w3.org/2000/svg" class="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">										<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />									</svg>									<span class="mini-cart-count absolute -top-2 -right-2 bg-accent-600 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center">										<?php echo esc_html( WC()->cart->get_cart_contents_count() ); ?>									</span>								</a>								<div class="mini-cart-dropdown hidden absolute right-0 top-full mt-2 w-80 bg-white dark:bg-dark-700 shadow-medium rounded-lg z-50">									<div class="widget_shopping_cart_content">										<?php woocommerce_mini_cart(); ?>									</div>								</div>							</div>						<?php endif; ?>						<?php if ( get_theme_mod( 'aqualuxe_enable_multilingual', false ) && function_exists( 'aqualuxe_language_switcher' ) ) : ?>							<div class="language-switcher-wrapper relative">								<?php aqualuxe_language_switcher(); ?>							</div>						<?php endif; ?>						<button id="mobile-menu-toggle" class="mobile-menu-toggle lg:hidden text-gray-700 dark:text-gray-300 hover:text-primary-600 dark:hover:text-primary-400 transition-colors duration-300" aria-label="<?php esc_attr_e( 'Toggle mobile menu', 'aqualuxe' ); ?>">							<svg xmlns="http://www.w3.org/2000/svg" class="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">								<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16" />							</svg>						</button>					</div><!-- .header-actions -->				</div>			</div>		</div><!-- .header-main -->		<?php get_template_part( 'templates/parts/header', 'mobile-menu' ); ?>		<?php get_template_part( 'templates/parts/header', 'search' ); ?>	</header><!-- #masthead -->	<?php do_action( 'aqualuxe_after_header' ); ?>	<div id="content" class="site-content">